import { Command }          from 'commander';
import { Registry }          from '../../registry/Registry.js';
import { decode as engineDecode } from '../../registry/CoreEngine.js';

export function pinCommand(program: Command): void {
  program
    .command('pin <key>')
    .description('Show full decoded details for an error by its amend: key')
    .action((keyInput: string) => {
      const cleanKey = keyInput.replace(/^--/, '');
      const searchKey = cleanKey.startsWith('amend:') ? cleanKey : `amend:${cleanKey}`;

      const matches = Registry.getInstance().find(searchKey);

      if (matches.length === 0) {
        // Fallback: try to decode directly without a registry entry
        try {
          const d = engineDecode(searchKey);
          console.log(`[amend pin ${searchKey}]  (not in local registry)\n`);
          console.log(`  Message    : ${d.message}`);
          console.log(`  ErrorClass : ${d.errorClass}`);
          console.log(`  File       : ${d.filePath}:${d.line}`);
          console.log(`  Function   : ${d.funcName}`);
        } catch {
          console.log(`No error found for key: ${cleanKey}`);
        }
        return;
      }

      const r = matches[matches.length - 1];

      console.log(`[amend pin ${r.key}]\n`);
      console.log(`  Message    : ${r.message}`);
      console.log(`  ErrorClass : ${r.errorClass}`);
      console.log(`  File       : ${r.filePath}:${r.line}`);
      console.log(`  Function   : ${r.funcName}`);
      console.log(`  Timestamp  : ${r.timestamp}`);
      console.log(`  Count      : ${r.count}`);
      console.log(`  Context    : ${r.context ?? '(none)'}`);
      console.log(`  Metadata   : ${r.metadata.length ? JSON.stringify(r.metadata, null, 4) : '(none)'}`);
    });
}
